import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Alert } from '../components/Shared';

const AuthPage = () => {
  const [tab, setTab] = useState('login');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [registerForm, setRegisterForm] = useState({
    name: '', email: '', password: '', confirmPassword: '',
    role: 'DONOR', phone: '', organization: '',
  });

  const { login, register } = useAuth();
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    if (!loginForm.email || !loginForm.password) return setError('Please fill in all fields.');
    setLoading(true);
    try {
      await login(loginForm.email, loginForm.password);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    const { name, email, password, confirmPassword, role, phone, organization } = registerForm;
    if (!name || !email || !password) return setError('Name, email, and password are required.');
    if (password !== confirmPassword) return setError('Passwords do not match.');
    if (password.length < 6) return setError('Password must be at least 6 characters.');
    setLoading(true);
    try {
      await register({ name, email, password, role, phone, organization });
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const quickFill = (email, password) => {
    setLoginForm({ email, password });
    setTab('login');
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-logo">
          <span className="logo-emoji">🌿</span>
          <h1>FoodBridge</h1>
          <p>Connecting donors with communities in need</p>
        </div>

        <div className="auth-tabs">
          <button className={`auth-tab ${tab === 'login' ? 'active' : ''}`} onClick={() => { setTab('login'); setError(''); }}>
            Sign In
          </button>
          <button className={`auth-tab ${tab === 'register' ? 'active' : ''}`} onClick={() => { setTab('register'); setError(''); }}>
            Register
          </button>
        </div>

        {error && <Alert type="error">{error}</Alert>}

        {tab === 'login' ? (
          <form onSubmit={handleLogin}>
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <input
                className="form-input" type="email" placeholder="you@example.com"
                value={loginForm.email} onChange={(e) => setLoginForm({ ...loginForm, email: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <input
                className="form-input" type="password" placeholder="••••••••"
                value={loginForm.password} onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}
              />
            </div>
            <button className="btn btn-primary btn-block btn-lg" type="submit" disabled={loading}>
              {loading ? 'Signing in…' : '🔐 Sign In'}
            </button>
          </form>
        ) : (
          <form onSubmit={handleRegister}>
            <div className="form-group">
              <label className="form-label">Full Name / Organization</label>
              <input
                className="form-input" type="text" placeholder="Green Valley Restaurant"
                value={registerForm.name} onChange={(e) => setRegisterForm({ ...registerForm, name: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label className="form-label">Email Address</label>
              <input
                className="form-input" type="email" placeholder="you@example.com"
                value={registerForm.email} onChange={(e) => setRegisterForm({ ...registerForm, email: e.target.value })}
              />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Password</label>
                <input
                  className="form-input" type="password" placeholder="Min. 6 characters"
                  value={registerForm.password} onChange={(e) => setRegisterForm({ ...registerForm, password: e.target.value })}
                />
              </div>
              <div className="form-group">
                <label className="form-label">Confirm Password</label>
                <input
                  className="form-input" type="password" placeholder="Repeat password"
                  value={registerForm.confirmPassword} onChange={(e) => setRegisterForm({ ...registerForm, confirmPassword: e.target.value })}
                />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">I am a…</label>
              <select
                className="form-select"
                value={registerForm.role} onChange={(e) => setRegisterForm({ ...registerForm, role: e.target.value })}
              >
                <option value="DONOR">🍽️ Food Donor (Restaurant / Individual)</option>
                <option value="NGO">🤝 NGO / Food Bank</option>
              </select>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Phone (optional)</label>
                <input
                  className="form-input" type="tel" placeholder="+1-555-000-0000"
                  value={registerForm.phone} onChange={(e) => setRegisterForm({ ...registerForm, phone: e.target.value })}
                />
              </div>
              <div className="form-group">
                <label className="form-label">Organization (optional)</label>
                <input
                  className="form-input" type="text" placeholder="Your org name"
                  value={registerForm.organization} onChange={(e) => setRegisterForm({ ...registerForm, organization: e.target.value })}
                />
              </div>
            </div>
            <button className="btn btn-primary btn-block btn-lg" type="submit" disabled={loading}>
              {loading ? 'Creating account…' : '🌱 Create Account'}
            </button>
          </form>
        )}

        {/* Quick Login Shortcuts */}
        <div style={{ marginTop: '20px', padding: '14px', background: 'var(--gray-50)', borderRadius: 'var(--radius)', border: '1px solid var(--gray-200)' }}>
          <p style={{ fontSize: '11px', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--gray-400)', marginBottom: '10px' }}>
            🧪 Quick Demo Login
          </p>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
            {[
              { label: 'Admin', email: 'admin@foodwaste.com', pass: 'admin123', color: 'var(--red-500)' },
              { label: 'Donor', email: 'donor1@example.com', pass: 'donor123', color: 'var(--green-600)' },
              { label: 'NGO', email: 'ngo1@example.com', pass: 'ngo123', color: 'var(--blue-600)' },
            ].map((acc) => (
              <button
                key={acc.label}
                onClick={() => quickFill(acc.email, acc.pass)}
                style={{ padding: '4px 10px', fontSize: '11.5px', fontWeight: '600', borderRadius: '20px', border: `1.5px solid ${acc.color}`, background: 'white', color: acc.color, cursor: 'pointer' }}
              >
                {acc.label}
              </button>
            ))}
          </div>
        </div>
      </div>
